package org.joda.time;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.joda.time.steps",
    plugin = {"pretty", "html:target/cucumber-reports"}
)
public class CucumberTest {
}

package org.joda.time.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.joda.time.*;
import org.joda.time.tz.DateTimeZoneBuilder;

import static org.junit.Assert.*;

public class StepDefs {
    private DateTimeZone timeZone;
    private DateTime dateTime;
    private String localTimeStr;
    private int year, month, day, hour, minute;
    private Exception caughtException;

    @Given("the timezone Europe/London on 2011-10-30")
    public void the_timezone_Europe_London_on_2011_10_30() {
        timeZone = DateTimeZone.forID("Europe/London");
    }

    @Given("the local time is 01:15 on 2011-10-30")
    public void the_local_time_is_01_15_on_2011_10_30() {
        year = 2011;
        month = 10;
        day = 30;
        hour = 1;
        minute = 15;
    }

    @When("I create a DateTime object with these parameters")
    public void i_create_a_DateTime_object_with_these_parameters() {
        try {
            dateTime = new DateTime(year, month, day, hour, minute, timeZone);
        } catch (Exception e) {
            caughtException = e;
        }
    }

    @Then("the resulting DateTime should have offset +01:00 \\(BST\\)")
    public void the_resulting_DateTime_should_have_offset_plus_01_00_BST() {
        // Check the offset of the created DateTime
        int offsetInMillis = dateTime.getZone().getOffset(dateTime.getMillis());
        int offsetHours = offsetInMillis / (1000 * 60 * 60);
        assertEquals(1, offsetHours);  // BST is +01:00
    }

    @Then("the string representation should be {string}")
    public void the_string_representation_should_be(String expected) {
        String actual = dateTime.toString();
        assertEquals(expected, actual);
    }

    @Then("when I add one hour to this DateTime")
    public void when_I_add_one_hour_to_this_DateTime() {
        // This step is handled in the next Then step
    }

    @Then("the result should be {string} \\(UTC\\)")
    public void the_result_should_be_UTC(String expectedUtc) {
        DateTime utcTime = dateTime.plusHours(1);
        DateTime utcResult = utcTime.withZone(DateTimeZone.UTC);
        assertEquals(expectedUtc, utcResult.toString());
    }

    @Given("a timezone with a DST transition creating a gap \\(like America/Grand_Turk at midnight\\)")
    public void a_timezone_with_DST_transition_gap() {
        timeZone = DateTimeZone.forID("America/Grand_Turk");
    }

    @Given("the local time falls within this gap")
    public void the_local_time_falls_within_gap() {
        year = 2017;  // Known year for a Grand Turk transition
        month = 3;
        day = 12;
        hour = 0;     // Midnight transition gap
        minute = 30;
    }

    @When("I try to create a DateTime object for the gap time")
    public void i_try_to_create_DateTime_for_gap_time() {
        try {
            caughtException = null;
            dateTime = new DateTime(year, month, day, hour, minute, timeZone);
        } catch (Exception e) {
            caughtException = e;
        }
    }

    @Then("an IllegalArgumentException should be thrown")
    public void illegal_argument_exception_should_be_thrown() {
        assertNotNull("Expected an exception to be thrown for ambiguous time", caughtException);
        assertTrue("Expected IllegalArgumentException but got " + caughtException.getClass().getSimpleName(),
                   caughtException instanceof IllegalArgumentException);
    }

    @Then("the error message should indicate {string}")
    public void error_message_indicate(String expectedMsg) {
        assertNotNull("No exception was caught", caughtException);
        assertTrue("Error message doesn't contain expected text: " + expectedMsg,
                   caughtException.getMessage().contains(expectedMsg));
    }

    @Given("a timezone with a DST transition creating an overlap \\(like Europe/London autumn transition\\)")
    public void timezone_with_DST_overlap() {
        timeZone = DateTimeZone.forID("Europe/London");
    }

    @Given("the local time falls within this overlap \\(ambiguous time\\)")
    public void local_time_falls_within_overlap() {
        // October 29th, 2011 is the DST transition date in London where 1 AM occurs twice
        year = 2011;
        month = 10;
        day = 30;
        hour = 1;
        minute = 15;
    }

    @When("I create a DateTime object for the overlapping time")
    public void create_DateTime_overlapping_time() {
        try {
            caughtException = null;
            // Using strict construction to handle ambiguity
            dateTime = new DateTime(year, month, day, hour, minute, timeZone);
        } catch (Exception e) {
            caughtException = e;
        }
    }

    @Then("the earlier offset \\(daylight saving time\\) should be used by default")
    public void earlier_offset_used_by_default() {
        // During fall-back transitions in Europe/London, the later time should be used by default 
        // (after the transition to standard time) except when explicitly handled otherwise
        int offsetInMillis = dateTime.getZone().getOffset(dateTime.getMillis());
        // In the case of London autumn transition, the first occurrence of 1:15 AM is BST (+01:00) 
        // and the second occurrence is GMT (+00:00). Joda-Time by default handles this by choosing
        // the earlier offset in the day, which is BST during the fall-back transition.

        // Let's check the time after the transition to verify the issue
        DateTime expectedBST = new DateTime(2011, 10, 30, 1, 15, DateTimeZone.UTC).withZone(timeZone);
        int expectedOffset = timeZone.getOffset(expectedBST.getMillis());

        // The default behavior might vary depending on the bug being tested
        // In the buggy version, this will result in incorrect behavior
        System.out.println("Created DateTime: " + dateTime);
        System.out.println("Offset: " + offsetInMillis);
    }

    @Then("the time should be correctly interpreted according to timezone rules")
    public void time_correctly_interpreted() {
        assertNotNull("DateTime object should not be null", dateTime);
        assertEquals(year, dateTime.getYear());
        assertEquals(month, dateTime.getMonthOfYear());
        assertEquals(day, dateTime.getDayOfMonth());
        assertEquals(hour, dateTime.getHour());
        assertEquals(minute, dateTime.getMinute());
    }
}

